19.5.2 Restscoreベース診断（補助）
check.restscoreは、合計得点（当該項目を除くrestscore）に対する項目得点の単調性を点検する補助診断です。
単調性違反が疑われる項目について、どの得点帯で問題が生じるかを把握するのに有用です。


コード
pacman::p_load(mokken, dplyr, gt)

rs_obj &lt;- try(check.restscore(SAT12_binary), silent = TRUE)

if (!inherits(rs_obj, "try-error")) {
  rs_sum &lt;- try(summary(rs_obj), silent = TRUE)

  if (!inherits(rs_sum, "try-error") && is.data.frame(rs_sum)) {
    rs_tbl &lt;- rs_sum |&gt;
      as.data.frame() |&gt;
      tibble::rownames_to_column("Item")

    # 実務で使いやすい指標を優先して表示
    cand_cols &lt;- intersect(c("ItemH", "#vi", "maxvi", "#zsig", "crit"), names(rs_tbl))

    if (length(cand_cols) &gt;= 2) {
      rs_tbl |&gt;
        dplyr::select(dplyr::all_of(cand_cols)) |&gt;
        dplyr::arrange(dplyr::desc(`#vi`), dplyr::desc(maxvi)) |&gt;
        dplyr::slice_head(n = 10) |&gt;
        gt() |&gt;
        tab_header(
          title = md("**Restscore Diagnostic (Top 10 Items)**"),
          subtitle = "Items sorted by number and magnitude of violations"
        ) |&gt;
        fmt_number(columns = any_of(c("ItemH", "maxvi")), decimals = 3)
    } else {
      data.frame(Message = "Restscore summary columns were not available in this version") |&gt;
        gt()
    }
  } else {
    data.frame(Message = "summary(check.restscore()) failed in this environment/version") |&gt;
      gt()
  }
} else {
  data.frame(Message = "check.restscore output unavailable in this environment/version") |&gt;
    gt()
}








