22.8 カテゴリ統合の提案（希少/乱れの是正）


コード
pacman::p_load(eRm)
# しきい値逆転や希少カテゴリがある項目に対し、隣接カテゴリを統合する案を作成
min_prop &lt;- 0.05
# 必要なら割合表を作成
if (!exists('prop_data')) {
  item_stats &lt;- itemstats(SAT12)
  prop_data &lt;- item_stats$proportions |&gt;
    as.data.frame() |&gt;
    dplyr::mutate(Item = paste0('Item', 1:nrow(item_stats$proportions))) |&gt;
    dplyr::select(Item, dplyr::everything())
}
rare_map &lt;- prop_data |&gt;
  pivot_longer(-Item, names_to='cat', values_to='prop') |&gt;
  group_by(Item) |&gt;
  summarise(Rare = any(prop &lt; min_prop))

bad_thresh &lt;- (
  if (exists('order_check') && nrow(order_check)) {
    dplyr::filter(order_check, !Ordered) |&gt;
      dplyr::select(Item)
  } else {
    data.frame(Item=character())
  }
)

targets &lt;- union(rare_map$Item[rare_map$Rare], bad_thresh$Item)
