# 統合は実務判断が必要。例: 1と2をまとめる、4と5をまとめる等

# （応用）統合案の自動生成のたたき台
# disorderedなら最小ギャップに対応する閾の両側カテゴリ統合案を提示
suggest_collapses &lt;- function(order_check, prop_tbl, min_prop = 0.05){
  # order_check: from threshold-order-check
  # prop_tbl:    proportions by item (same structure as prop_data)
  bcols &lt;- grep('^b[0-9]+$', colnames(order_check), value = TRUE)
  # 最小ギャップの位置
  find_min_gap_idx &lt;- function(x){
    d &lt;- diff(as.numeric(x)); which.min(d)
  }
  oc &lt;- order_check |&gt;
    filter(!Ordered)
  if(nrow(oc) == 0) return(data.frame())
  collapse_list &lt;- lapply(seq_len(nrow(oc)), function(i){
    it &lt;- oc$Item[i]
    idx &lt;- find_min_gap_idx(oc[i, bcols])
    # 例: idx=2ならカテゴリ(2,3)の統合案
    # さらに希少カテゴリがある場合は、そのカテゴリを隣と統合
    pr &lt;- prop_tbl |&gt;
      filter(Item == it) |&gt;
      pivot_longer(-Item, names_to='cat', values_to='prop')
    rare_cats &lt;- pr$cat[pr$prop &lt; min_prop]
    data.frame(Item = it,
               Suggestion = paste0('Merge categories around threshold ', idx,
                                   ' (e.g., ', idx, ' & ', idx+1, ')',
                                   if(length(rare_cats)&gt;0)
                                     paste0(' + rare: ', paste(rare_cats, collapse=',')) else ''))
  })
  if (length(collapse_list)) dplyr::bind_rows(collapse_list) else data.frame()
}

